import React from "react"
import { PageLayout, PageTitle } from "../components"
import { Container, Image } from "react-bootstrap"
import { Link, graphql } from "gatsby"
import { SEO } from "../utils"

export default ({ data }) => {
  const MediaLink = ({ title, author, link }) => (
    <li key={title} style={{ color: "gray" }}>
      <a rel="noopener noreferrer" href={link}>
        {title}
      </a>
      &nbsp;-<i>{author}</i>
    </li>
  )

  const {
    author,
    occupation,
    gameList,
    showsList,
    designations,
    unemployed,
  } = data.site.siteMetadata
  //const { toString } = useContext(ThemeContext)

  const gameLinks = gameList.map(book => MediaLink(book))
  const showLinks = showsList.map(show => MediaLink(show))

  return (
    <PageLayout>
      <SEO title="About Me" />
      <PageTitle title="About Me" />
      <Container>
        <Image
          roundedCircle
          width="180"
          height="180"
          src={`../../icons/sovan.png`}
          alt={author}
        />
        <article className="w-75 m-auto pt-2 text-justify">
          <p className="text-center">
            {designations.map((attr, i) => (
              <span key={attr}>
                &nbsp;<b>{attr}</b>&nbsp;
                {i < designations.length - 1 && <>|</>}
              </span>
            ))}
          </p>
          <p className="i-5 mt-4 pt-2">
            Hey! My name is <b>{`${author}`}</b>. 
            I love technology. The colossal amount of complexity, intricacy and profundity it adds to human life fascinates me. 
            From leading and driving personal projects in robotics, to learning programming languages, and researching new algorithms, 
            I have always been passionate about technology as a tool to improve human life.
          </p>
          <p className="i-5">
            As a <b>{occupation}ing</b> student at the University of Waterloo, 
            I have developed technical aptitude in numerous programming languages such as 
            C++, Python, HTML5, CSS, and JavaScript, with an interest in cryptography, blockchain and game development.
          </p>
          <p className="i-5">
            My internship experiences at BMO Financial Group has made me adept with task automation, 
            configuration management frameworks and data pipelines, with data cleaning, assimilation, 
            and pre-processing using PowerShell, Python (Pandas, NumPy, SciPy) and C++.
          </p>
          <p className="i-5">
            Additionally, I have hands on hardware experience through FIRST and VEX Robotics 
            where I gained proficiency in 3D printing, CNC milling, 
            laser cutting, wiring, soldering, electrical instrumentation, and machining.
          </p>
          <p className="i-5">
            Most importantly, I possess an entrenched, unwavering aspiration to become a technologist 
            that will impart a wave of positive change across the world.
          </p>
          <p className="i-5">
            In my spare time, I love working on personal projects, managing clubs and organizations, 
            watching tv-shows and playing video games :)
          </p>
          <p className="i-5">
            Check out my <Link to="/projects">projects</Link> to see what I've
            been up to! Or check out my&nbsp;
            <a
              href="https://linkedin.com/in/sovan-patnayak/"
              target="_blank"
              rel="noopener noreferrer"
            >
             LinkedIn 
            </a>
            &nbsp;to see what's recently caught my eye or to learn more about me! 
          </p>
        </article>
        <article className="w-75 m-auto">
          {unemployed && (
            <>
              <hr />
              <p className="unemployed">
                <small>
                  I am <b>currently looking for Winter 2021 Co-op opportunities</b>! If you
                  like what you <Link to="/resume">see</Link>, let's get
                  in&nbsp;
                  <a
                    href="mailto:sovanpatnayak@gmail.com"
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    touch
                  </a>
                  !
                </small>
              </p>
            </>
          )}
          <hr />
          <h5 className="game-list-title pt-1">
            Here are a couple of my all-time favourite games:
          </h5>
          <ul style={{ fontSize: "0.9rem", listStyle: "none" }}>{gameLinks}</ul>
          <h5 className="show-list-title pt-2">
            Here are a couple of binge-worthy shows:
          </h5>
          <ul style={{ fontSize: "0.9rem", listStyle: "none" }}>{showLinks}</ul>
          <h5 className="movie-list-title pt-3">
            Here are a couple of movies that I love:
          </h5>
          <p>
            <i>...waaaay too many to list.</i>
          </p>
        </article>
      </Container>
    </PageLayout>
  )
}

export const query = graphql`
  query {
    site {
      siteMetadata {
        unemployed
        occupation
        author
        designations
        gameList {
          title
          author
          link
        }
        showsList {
          title
          author
          link
        }
      }
    }
  }
`
